import Signal from "@rbxts/lemon-signal";

type Constructable<T> = new (...args: Parameters<T>) => T;

interface MaidStatic {
	Is: <T extends object>(object: unknown) => object is Maid<T>;
}
export type MaidConstructor = (new <U extends object | void = void>() => Maid<U> & MaidStatic) & MaidStatic;

/**
 * A class to manage the connections in your game
 */
export interface Maid<U extends object | void = void> {
	/**
	 * Whether or not the Maid is currently cleaning up.
	 */
	readonly CurrentlyCleaning: boolean;

	/**
	 * Whether or not you want to suppress the re-destroying of instances.
	 * Default is `false`, which is the original behavior.
	 */
	SuppressInstanceReDestroy: boolean;

	/**
	 * Whether or not to use the unsafe fast defer function for cleaning up
	 * threads. This might be able to throw, so be careful. If you're getting
	 * any thread related errors, chances are it is this.
	 */
	UnsafeThreadCleanup: boolean;

	/**
	 * Creates a new child Maid that will be automatically cleaned up when this
	 * parent Maid is cleaned up. This is an alias for {@linkcode sub}.
	 *
	 * Additionally, if the child gets destroyed on its own, it will remove itself from the parent node, freeing up memory.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const parentMaid = new Maid();
	 * const childMaid = parentMaid.Extend();
	 *
	 * // Add objects to both
	 * parentMaid.Add(() => print("Parent cleanup"), true);
	 * childMaid.Add(() => print("Child cleanup"), true);
	 *
	 * // When parent is cleaned up, child is also cleaned up
	 * parentMaid.Cleanup(); // Prints both "Parent cleanup" and "Child cleanup"
	 *
	 * @returns A new child Maid instance that will be cleaned up when this Maid is cleaned up
	 */
	Extend<U extends object | void = void>(): Maid<U>;

	/**
	 * Creates a new child Maid that will be automatically cleaned up when this
	 * parent Maid is cleaned up. This is an alias for {@linkcode Extend}.
	 *
	 * Additionally, if the child gets destroyed on its own, it will remove itself from the parent node, freeing up memory.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const mainMaid = new Maid();
	 * const pathMaid = mainMaid.sub();
	 *
	 * // Add path-specific cleanup to the sub-maid
	 * pathMaid.Add(preUpdateConnection, "Disconnect");
	 * pathMaid.Add(destroyedConnection, "Disconnect");
	 *
	 * // When main maid is cleaned up, path maid is also cleaned up
	 * mainMaid.Cleanup(); // Cleans up both main and path-specific objects
	 *
	 * @returns A new child Maid instance that will be cleaned up when this Maid is cleaned up
	 */
	sub<U extends object | void = void>(): Maid<U>;

	/**
	 * Marks another Maid as a child of this Maid, establishing a parent-child
	 * relationship. The child Maid will be automatically cleaned up when this
	 * parent Maid is cleaned up, or if destroyed on its own will remove itself from the parent node, freeing up memory.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const parentMaid = new Maid();
	 * const childMaid = new Maid();
	 *
	 * // Manually establish parent-child relationship
	 * parentMaid.MarkChild(childMaid);
	 *
	 * // Child will be cleaned up when parent is cleaned up
	 * parentMaid.Cleanup(); // Also cleans up childMaid
	 *
	 * @param child The Maid to mark as a child of this Maid
	 */
	MarkChild(child: Maid): void;

	/**
	 * Checks if the specified Maid is a parent of this Maid in the parent-child
	 * hierarchy.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const parentMaid = new Maid();
	 * const childMaid = parentMaid.sub();
	 *
	 * print(childMaid.IsParent(parentMaid)); // true
	 * print(parentMaid.IsParent(childMaid)); // false
	 *
	 * // Useful for preventing circular references
	 * class RigidBody {
	 *     SetParent(body: RigidBody) {
	 *         if (this.IsParent(body)) return; // Prevent circular reference
	 *         // ... rest of implementation
	 *     }
	 * }
	 *
	 * @param parent The Maid to check if it's a parent of this Maid
	 * @returns `true` if the specified Maid is a parent of this Maid, `false` otherwise
	 */
	IsParent(parent: Maid): boolean;

	/**
	 * Returns the internal state of the Maid for debugging purposes. This
	 * creates a clone of the internal object-to-method mapping with the
	 * metatable removed.
	 *
	 * :::warning Debug Only
	 * This method is intended for debugging and internal inspection only.
	 * The returned object should not be used for normal Maid operations.
	 * :::
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const maid = new Maid();
	 * const connection = someEvent.Connect(() => {});
	 * maid.Add(connection, "Disconnect");
	 *
	 * // For debugging - see what objects are tracked
	 * const internals = maid.GetInternals();
	 * print(internals); // Shows the internal object-to-method mapping
	 *
	 * @returns A Map-like object containing the internal object-to-method mappings
	 */
	GetInternals(): Map<object, string | boolean>;

	/**
	 * Adds an {@linkcode object} to Maid for later cleanup, where
	 * {@linkcode methodName} is the key of the method within {@linkcode object}
	 * which should be called at cleanup time.
	 *
	 * If the {@linkcode methodName} is `true` the {@linkcode object} itself
	 * will be either called if it is a function or have `task.cancel` called on
	 * it if it is a thread.
	 *
	 * If passed an {@linkcode index} it will occupy a namespace which can be
	 * {@linkcode Maid.Remove}'d or overwritten. Returns the
	 * {@linkcode object}.
	 *
	 * @example
	 * import { Workspace, TweenService } from "@rbxts/services";
	 * import { Maid } from "shared/maid";
	 *
	 * const obliterator = new Maid<{ CurrentTween: Tween }>();
	 * const part = Workspace.FindFirstChild("Part") as Part;
	 *
	 * // Queue the part to be Destroyed at Cleanup time
	 * obliterator.Add(part, "Destroy");
	 *
	 * // Queue function to be called with `true` methodName
	 * obliterator.Add(print, true);
	 *
	 * // Close a thread.
	 * obliterator.Add(task.defer(() => {
	 * 		while (true) {
	 * 			 print("Running!");
	 * 			task.wait(0.5);
	 * 		}
	 * }), true);
	 *
	 * // This implementation allows you to specify behavior for any object
	 * obliterator.Add(TweenService.Create(part, new TweenInfo(1), { Size: Vector3.one }), "Cancel");
	 *
	 * // By passing an index, the object will occupy a namespace
	 * // If "CurrentTween" already exists, it will call :Remove("CurrentTween") before writing
	 * obliterator.Add(TweenService.Create(part, new TweenInfo(1), { Size: Vector3.one }), "Destroy", "CurrentTween");
	 *
	 * @param object The object you want to clean up.
	 * @param methodName The name of the method that will be used to clean up. If not passed, it will first check if the object's type exists in TypeDefaults, and if that doesn't exist, it assumes `Destroy`.
	 * @param index The index that can be used to clean up the object manually.
	 * @returns The object that was passed as the first argument.
	 */
	Add<
		O extends keyof U extends never
			? object
			: I extends keyof U
				? U[I]
				: M extends true
					? Callback | thread
					: M extends undefined
						? { Destroy(): void } | RBXScriptConnection
						: object,
		M extends ((_: O) => void) | ((this: O) => void) | ExtractKeys<O, () => void> | true | undefined,
		I extends keyof U | undefined = undefined,
	>(
		object: O,
		methodName?: M,
		index?: I,
		priority?: number,
	): O;

	add<
		O extends keyof U extends never
			? object
			: I extends keyof U
				? U[I]
				: M extends true
					? Callback | thread
					: M extends undefined
						? { Destroy(): void } | RBXScriptConnection
						: object,
		M extends ((_: O) => void) | ((this: O) => void) | ExtractKeys<O, () => void> | true | undefined,
		I extends keyof U | undefined = undefined,
	>(
		object: O,
		methodName?: M,
		index?: I,
		priority?: number,
	): O;

	<
		O extends keyof U extends never
			? object
			: I extends keyof U
				? U[I]
				: M extends true
					? Callback | thread
					: M extends undefined
						? { Destroy(): void } | RBXScriptConnection
						: object,
		M extends ((_: O) => void) | ((this: O) => void) | ExtractKeys<O, () => void> | true | undefined,
		I extends keyof U | undefined = undefined,
	>(
		object: O,
		methodName?: M,
		index?: I,
		priority?: number,
	): O;

	/**
	 * Connects {@linkcode callback} to {@linkcode signal} and adds it into the {@linkcode Maid}
	 * 
	 * @param signal the signal to connect
	 * @param callback the function to connect to the signal
	 * @param disconnectName the disconnect methodname of the connection
	 */
	on<T extends defined[]>(signal: Signal<T> | RBXScriptSignal, callback: (...args: any[]) => void, disconnectName?: string): void;

	/**
	 * Adds an {@linkcode object} to Maid for later cleanup, where
	 * {@linkcode methodName} is the key of the method within {@linkcode object}
	 * which should be called at cleanup time.
	 *
	 * @param priority The priority of the object.
	 * @param object The object you want to clean up.
	 * @param methodName The name of the method that will be used to clean up. If not passed, it will first check if the object's type exists in TypeDefaults, and if that doesn't exist, it assumes `Destroy`.
	 * @param index The index that can be used to clean up the object manually.
	 * @returns The object that was passed as the first argument.
	 */
	PriorityAdd<
		O extends keyof U extends never
			? object
			: I extends keyof U
				? U[I]
				: M extends true
					? Callback | thread
					: M extends undefined
						? { Destroy(): void } | RBXScriptConnection
						: object,
		M extends ((_: O) => void) | ((this: O) => void) | ExtractKeys<O, () => void> | true | undefined,
		I extends keyof U | undefined = undefined,
	>(
		priority: number,
		object: O,
		methodName?: M,
		index?: I,
	): O;

	/**
	 * Adds a {@linkcode Promise} to the Maid. If the Maid is cleaned up and the
	 * {@linkcode Promise} is not completed, the {@linkcode Promise} will be cancelled.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const obliterator = new Maid();
	 * obliterator.AddPromise(Promise.delay(3)).andThenCall(print, "Finished!").catch(warn);
	 * task.wait(1);
	 * obliterator.Cleanup();
	 *
	 * @param promise The {@linkcode Promise} you want to add to the maid.
	 * @param index The index that can be used to clean up the promise manually.
	 * @returns The {@linkcode promise} that was passed
	 */
	AddPromise<
		// if you are curious how this works, here's a quick breakdown:
		// If `U` has no predefined keys (e.g., `U` is `void` or `{}`)
		// 	- Then `P` can be any Promise
		// elseif `U` has keys:
		// 	- If index `I` is one of those keys
		// 		- Then `P` must be of the type `U[I]` (which implies `U[I]` should be a Promise type)
		// 		- Else (`I` is undefined or not a key of `U`), `P` can be any Promise
		P extends keyof U extends never ? Promise<unknown> : I extends keyof U ? U[I] : Promise<unknown>,
		I extends keyof U | undefined = undefined,
	>(
		promise: P,
		index?: I,
	): P;

	promise<
		// if you are curious how this works, here's a quick breakdown:
		// If `U` has no predefined keys (e.g., `U` is `void` or `{}`)
		// 	- Then `P` can be any Promise
		// elseif `U` has keys:
		// 	- If index `I` is one of those keys
		// 		- Then `P` must be of the type `U[I]` (which implies `U[I]` should be a Promise type)
		// 		- Else (`I` is undefined or not a key of `U`), `P` can be any Promise
		P extends keyof U extends never ? Promise<unknown> : I extends keyof U ? U[I] : Promise<unknown>,
		I extends keyof U | undefined = undefined,
	>(
		promise: P,
		index?: I,
	): P;

	/**
	 * Constructs an object for you and adds it to the Maid. It's really
	 * just "shorthand" for `maid.Add(new Object(), methodName, index)`.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const obliterator = new Maid();
	 * const subObliterator = obliterator.AddObject(Maid, "Destroy");
	 *
	 * @param object The constructable class for the object you want to add to the Maid.
	 * @param methodName The name of the method that will be used to clean up. If not passed, it will first check if the object's type exists in TypeDefaults, and if that doesn't exist, it assumes `Destroy`.
	 * @param index The index that can be used to clean up the object manually.
	 * @param parameters The arguments used to create the class.
	 * @returns The new constructed object from the passed {@linkcode object} class.
	 */
	AddObject<
		O extends Constructable<unknown>,
		T extends InstanceType<O>,
		M extends ExtractKeys<T, () => void> | true | undefined,
		I extends keyof U | undefined = undefined,
	>(
		object: O,
		methodName?: M,
		index?: I,
		...parameters: ConstructorParameters<O>
	): T;

	/**
	 * Cleans up whatever `object` was set to this namespace by the 3rd
	 * parameter of {@linkcode Maid.Add}.
	 *
	 * @example
	 * import { Workspace } from "@rbxts/services";
	 * import { Maid } from "shared/maid";
	 *
	 * const obliterator = new Maid<{ Baseplate: Part }>();
	 * obliterator.Add(Workspace.FindFirstChild("Baseplate") as Part, "Destroy", "Baseplate");
	 * obliterator.Remove("Baseplate");
	 *
	 * @param index The index you want to remove.
	 * @returns The same {@linkcode Maid}, for chaining reasons.
	 */
	Remove(index: keyof U): this;

	/**
	 * Removes an object from the {@linkcode Maid} without running a cleanup.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const obliterator = new Maid<{ readonly Function: () => void }>();
	 * obliterator.Add(() => print("Removed!"), true, "Function");
	 *
	 * obliterator.RemoveNoClean("Function"); // Does not print.
	 *
	 * @param index The index you are removing.
	 * @returns The same {@linkcode Maid}, for chaining reasons.
	 */
	RemoveNoClean(index: keyof U): this;

	/**
	 * Cleans up multiple objects at once.
	 * @param indices The indices you want to remove.
	 * @returns The same {@linkcode Maid}, for chaining reasons.
	 */
	RemoveList(...indices: Array<keyof U>): this;

	/**
	 * Cleans up multiple objects at once without running their cleanup.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * type NoOp = () => void
	 *
	 * const obliterator = new Maid<{ One: NoOp, Two: NoOp, Three: NoOp }>();
	 * obliterator.Add(() => print("Removed One"), true, "One");
	 * obliterator.Add(() => print("Removed Two"), true, "Two");
	 * obliterator.Add(() => print("Removed Three"), true, "Three");
	 *
	 * obliterator.RemoveListNoClean("One", "Two", "Three"); // Nothing is printed.
	 *
	 * @param indices The indices you want to remove.
	 * @returns The same {@linkcode Maid}, for chaining reasons.
	 */
	RemoveListNoClean(...indices: Array<keyof U>): this;

	/**
	 * Gets whatever object is stored with the given {@linkcode index}, if it exists. This
	 * was added since Maid allows getting the task using `__index`.
	 *
	 * @example
	 * import { Workspace } from "@rbxts/services";
	 * import { Maid } from "shared/maid";
	 *
	 * const obliterator = new Maid<{ Baseplate: Part }>();
	 * obliterator.Add(Workspace.FindFirstChild("Baseplate") as Part, "Destroy", "Baseplate");
	 * print(obliterator.Get("Baseplate")); // Returns Baseplate.
	 *
	 * @param index The index that the object is stored under.
	 * @returns This will return the object if it is found, but it won't return anything if it doesn't exist.
	 */
	Get<T extends keyof U>(index: T): U[T] | undefined;

	/**
	 * Returns a frozen copy of the Maid's indices.
	 *
	 * @example
	 * import { Workspace } from "@rbxts/services";
	 * import { Maid } from "shared/maid";
	 *
	 * const obliterator = new Maid<{ Baseplate: Part }>();
	 * obliterator.Add(Workspace.FindFirstChild("Baseplate") as Part, "Destroy", "Baseplate");
	 * print(obliterator.GetAll().Baseplate); // Prints Baseplate.
	 *
	 * @returns A frozen object containing all the indices and their corresponding objects.
	 */
	GetAll(): { readonly [P in keyof U]: U[P] | undefined };

	/**
	 * Calls each object's specified `methodName`. If `methodName` is `true`,
	 * the object itself will be invoked as a function or cancelled if it's a
	 * thread. Each object is then removed from the Maid, and the namespace
	 * is cleared. This method is also invoked when the Maid instance itself
	 * is called, allowing it to be used as a destructor callback.
	 */
	Cleanup(): void;
	cleanup(): void;

	/**
	 * Calls {@linkcode Maid.Cleanup} and renders the Maid unusable. Any
	 * further calls will throw an error.
	 */
	Destroy(): void;

	/**
	 * "Links" this Maid to an `Instance`, such that the Maid will
	 * {@linkcode Cleanup} when the `Instance` is {@linkcode Instance.Destroy}'d
	 * and garbage collected.
	 *
	 * A Maid may only be linked to one instance at a time, unless
	 * {@linkcode allowMultiple} is `true`.
	 *
	 * When called with a truthy {@linkcode allowMultiple} parameter, the
	 * Maid will "link" the Instance without overwriting any previous links,
	 * and will also not be overridable.
	 *
	 * When called with a falsy {@linkcode allowMultiple} parameter, the Maid
	 * will overwrite the previous link which was also called with a falsy
	 * {@linkcode allowMultiple} parameter, if applicable.
	 *
	 * @example
	 * import { Maid } from "shared/maid";
	 *
	 * const obliterator = new Maid();
	 * obliterator.Add(() => print("Cleaning up!"), true);
	 *
	 * {
	 * 	const folder = new Instance("Folder");
	 * 	obliterator.LinkToInstance(folder, false);
	 * 	folder.Destroy();
	 * }
	 *
	 * @param object The {@linkcode Instance} you want to link the Maid to.
	 * @param allowMultiple Whether or not to allow multiple links on the same Maid.
	 * @returns A {@linkcode RBXScriptConnection} that can be disconnected to prevent the cleanup of {@linkcode Maid.LinkToInstance}.
	 */
	LinkToInstance(object: Instance, allowMultiple: boolean): RBXScriptConnection;

	/**
	 * Links several instances to a maid, which is then returned.
	 * @param instances All the {@linkcode Instance}s you want linked.
	 * @returns A new {@linkcode Maid} that can be used to manually disconnect all LinkToInstances.
	 */
	LinkToInstances(...instances: Array<Instance>): Maid;
}

export const Maid: MaidConstructor;
